const recentLeads = $('Check Recent Lead Activity').all();
const recentEmails = $('Check Recent Email Logs').all();
const recentNotifs = $('Check Recent Notifications').all();

const hasRecentLeads = recentLeads.length > 0 && recentLeads[0].json.id;
const hasRecentEmails = recentEmails.length > 0 && recentEmails[0].json.id;
const hasRecentNotifs = recentNotifs.length > 0 && recentNotifs[0].json.id;

// Supabase is reachable if any query returned (even empty results)
const supabaseAlive = true; // if we got here, connection worked

const issues = [];

// Note: no recent leads/emails might just mean no new inquiries came in.
// The real check is whether Supabase is reachable and notifications are flowing.
// If notifications stopped, the system may have silently disconnected.

if (!hasRecentNotifs && !hasRecentLeads) {
  issues.push('No new leads OR notifications in the last 48 hours. If inquiries were expected, check that the Gmail trigger is still connected in n8n.');
}

const allHealthy = issues.length === 0;

let html = '<h2>Freedom Ryder CRM — Daily Health Check</h2>';
html += '<p><strong>Date:</strong> ' + new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' }) + '</p>';
html += '<hr>';

html += '<table border="1" cellpadding="8" style="border-collapse:collapse">';
html += '<tr style="background:#f0f0f0"><th>System</th><th>Status</th></tr>';
html += '<tr><td>Supabase Database</td><td style="color:green">Connected</td></tr>';
html += '<tr><td>Recent Leads (48h)</td><td>' + (hasRecentLeads ? '<span style="color:green">Yes</span>' : '<span style="color:orange">None</span>') + '</td></tr>';
html += '<tr><td>Recent Emails Sent (48h)</td><td>' + (hasRecentEmails ? '<span style="color:green">Yes</span>' : '<span style="color:orange">None</span>') + '</td></tr>';
html += '<tr><td>Recent Notifications (48h)</td><td>' + (hasRecentNotifs ? '<span style="color:green">Yes</span>' : '<span style="color:orange">None</span>') + '</td></tr>';
html += '</table>';

if (issues.length > 0) {
  html += '<br><h3 style="color:red">Issues Detected</h3><ul>';
  for (const issue of issues) {
    html += '<li>' + issue + '</li>';
  }
  html += '</ul>';
  html += '<p><strong>Action:</strong> Log into your n8n dashboard and check that all workflows are active and the Gmail trigger is connected.</p>';
} else {
  html += '<br><p style="color:green"><strong>All systems healthy.</strong> No action needed.</p>';
}

return [{ json: { allHealthy, issues, html, hasIssues: issues.length > 0 } }];
